  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground [a]:hover:bg-primary/80",
        outline:
          "border-border bg-background hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground dark:border-input dark:bg-input/30 dark:hover:bg-input/50",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80 aria-expanded:bg-secondary aria-expanded:text-secondary-foreground",
        ghost:
          "hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground dark:hover:bg-muted/50",
        destructive:
          "bg-destructive/10 text-destructive hover:bg-destructive/20 focus-visible:border-destructive/40 focus-visible:ring-destructive/20 dark:bg-destructive/20 dark:hover:bg-destructive/30 dark:focus-visible:ring-destructive/40",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default:
          "h-8 gap-1.5 px-2.5 has-data-[icon=inline-end]:pr-2 has-data-[icon=inline-start]:pl-2",
        xs: "h-6 gap-1 rounded-[min(var(--radius-md),10px)] px-2 text-xs in-data-[slot=button-group]:rounded-lg has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-3",
        sm: "h-7 gap-1 rounded-[min(var(--radius-md),12px)] px-2.5 text-[0.8rem] in-data-[slot=button-group]:rounded-lg has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-3.5",
        lg: "h-9 gap-1.5 px-2.5 has-data-[icon=inline-end]:pr-2 has-data-[icon=inline-start]:pl-2",
        icon: "size-8",
        "icon-xs":
          "size-6 rounded-[min(var(--radius-md),10px)] in-data-[slot=button-group]:rounded-lg [&_svg:not([class*='size-'])]:size-3",
        "icon-sm":
          "size-7 rounded-[min(var(--radius-md),12px)] in-data-[slot=button-group]:rounded-lg",
        "icon-lg": "size-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant = "default",
  size = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot.Root : "button"

  return (
    <Comp
      data-slot="button"
      data-variant={variant}
      data-size={size}
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  )
}

export { Button, buttonVariants }

import { createContext, useContext, useEffect, useState, type ReactNode } from 'react'
import type { Session } from '@supabase/supabase-js'
import { supabase } from '../lib/supabase'

export type UserRole = 'owner' | 'admin' | 'supervisor' | 'member' | 'guest'

export interface Profile {
  id: string
  name: string
  email: string
  role: UserRole
  is_active: boolean
}

interface ProfileContextType {
  profile: Profile | null
  loading: boolean
}

const ProfileContext = createContext<ProfileContextType>({ profile: null, loading: true })

export function ProfileProvider({ session, children }: { session: Session; children: ReactNode }) {
  const [profile, setProfile] = useState<Profile | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const fetchProfile = async () => {
      const { data } = await supabase
        .from('profiles')
        .select('id, name, email, role, is_active')
        .eq('email', session.user.email)
        .single()
      setProfile(data ?? null)
      setLoading(false)
    }
    fetchProfile()
  }, [session])

  return (
    <ProfileContext.Provider value={{ profile, loading }}>
      {children}
    </ProfileContext.Provider>
  )
}

export const useProfile = () => useContext(ProfileContext)

import { useState, useEffect } from 'react'
import { supabase } from '../lib/supabase'
import { Profile, UserRole } from '../context/ProfileContext'
import { 
  createColumnHelper,
  flexRender,
  getCoreRowModel,
  useReactTable,
} from '@tanstack/react-table'
import { Button } from '../components/ui/button'
import { Input } from '../components/ui/input'
import { Search, Plus, Edit2, X } from 'lucide-react'

// Define the columns using TanStack Table
const columnHelper = createColumnHelper<Profile>()

export default function UsersPage() {
  const [data, setData] = useState<Profile[]>([])
  const [loading, setLoading] = useState(true)

  // Modal state
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [editingProfile, setEditingProfile] = useState<Profile | null>(null)

  // Form state
  const [email, setEmail] = useState('')
  const [name, setName] = useState('')
  const [role, setRole] = useState<UserRole>('member')
  const [isActive, setIsActive] = useState(true)
  const [saving, setSaving] = useState(false)

  useEffect(() => {
    fetchProfiles()
  }, [])

  const fetchProfiles = async () => {
    setLoading(true)
    const { data: profiles, error } = await supabase
      .from('profiles')
      .select('*')
      .order('name')

    if (profiles) setData(profiles)
    setLoading(false)
  }

  const openAddModal = () => {
    setEditingProfile(null)
    setEmail('')
    setName('')
    setRole('member')
    setIsActive(true)
    setIsModalOpen(true)
  }

  const openEditModal = (profile: Profile) => {
    setEditingProfile(profile)
    setEmail(profile.email)
    setName(profile.name)
    setRole(profile.role)
    setIsActive(profile.is_active)
    setIsModalOpen(true)
  }

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault()
    setSaving(true)

    try {
      if (editingProfile) {
        // Update existing
        const { error } = await supabase
          .from('profiles')
          .update({ role, is_active: isActive })
          .eq('id', editingProfile.id)

        if (error) throw error
      } else {
        // Add new
        const { error } = await supabase
          .from('profiles')
          .insert({ email, name, role, is_active: isActive })

        if (error) throw error
      }

      setIsModalOpen(false)
      fetchProfiles()
    } catch (err) {
      console.error('Error saving profile:', err)
      alert('Error al guardar el perfil')
    } finally {
      setSaving(false)
    }
  }

  const columns = [
    columnHelper.accessor('name', {
      header: 'Nombre',
      cell: info => <span className="font-medium text-gray-900">{info.getValue() || '—'}</span>,
    }),
    columnHelper.accessor('email', {
      header: 'Correo Electrónico',
      cell: info => <span className="text-gray-500">{info.getValue()}</span>,
    }),
    columnHelper.accessor('role', {
      header: 'Rol',
      cell: info => {
        const role = info.getValue()
        return (
          <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-blue-50 text-blue-700 capitalize">
            {role}
          </span>
        )
      },
    }),
    columnHelper.accessor('is_active', {
      header: 'Estado',
      cell: info => {
        const active = info.getValue()
        return (
          <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${
            active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'
          }`}>
            {active ? 'Activo' : 'Inactivo'}
          </span>
        )
      },
    }),
    columnHelper.display({
      id: 'actions',
      header: '',
      cell: props => (
        <div className="flex justify-end pr-4">
          <button 
            onClick={() => openEditModal(props.row.original)}
            className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-md transition-colors"
          >
            <Edit2 size={16} />
          </button>
        </div>
      )
    })
  ]

  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
  })

  return (
    <div className="p-8 h-full flex flex-col max-w-6xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-semibold text-gray-900 mb-1">Gestión de Usuarios</h1>
          <p className="text-sm text-gray-500">
            Administre los perfiles de usuario, roles y niveles de acceso al sistema.
          </p>
        </div>
        <Button onClick={openAddModal} className="bg-blue-600 hover:bg-blue-700 text-white">
          <Plus size={16} className="mr-2" />
          Añadir Usuario
        </Button>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 bg-white rounded-xl border border-gray-200 overflow-hidden flex flex-col shadow-sm">
        {/* Table Toolbar */}
        <div className="p-4 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
          <div className="relative w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
            <Input 
              placeholder="Buscar usuarios..." 
              className="pl-9 h-9 bg-white"
            />
          </div>
        </div>

        {/* Tanstack Table */}
        <div className="flex-1 overflow-auto">
          {loading ? (
            <div className="flex items-center justify-center h-full">
              <div className="w-5 h-5 rounded-full border-2 border-blue-600 border-t-transparent animate-spin" />
            </div>
          ) : (
            <table className="w-full text-sm text-left">
              <thead className="text-xs text-gray-500 uppercase bg-gray-50 sticky top-0 border-b border-gray-200 z-10">
                {table.getHeaderGroups().map(headerGroup => (
                  <tr key={headerGroup.id}>
                    {headerGroup.headers.map(header => (
                      <th key={header.id} className="px-6 py-3.5 font-medium tracking-wider">
                        {header.isPlaceholder
                          ? null
                          : flexRender(
                              header.column.columnDef.header,
                              header.getContext()
                            )}
                      </th>
                    ))}
                  </tr>
                ))}
              </thead>
              <tbody className="divide-y divide-gray-100">
                {table.getRowModel().rows.map(row => (
                  <tr key={row.id} className="hover:bg-gray-50/50 transition-colors group">
                    {row.getVisibleCells().map(cell => (
                      <td key={cell.id} className="px-6 py-4 whitespace-nowrap">
                        {flexRender(cell.column.columnDef.cell, cell.getContext())}
                      </td>
                    ))}
                  </tr>
                ))}
                {data.length === 0 && (
                  <tr>
                    <td colSpan={columns.length} className="px-6 py-12 text-center text-gray-500">
                      No se encontraron usuarios
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in-95 duration-200">
            <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
              <h2 className="text-lg font-semibold text-gray-900">
                {editingProfile ? 'Editar Usuario' : 'Añadir Usuario'}
              </h2>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 transition-colors">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSave} className="p-6 flex flex-col gap-5">
              {!editingProfile && (
                <>
                  <div className="flex flex-col gap-2">
                    <label className="text-sm font-medium text-gray-700">Nombre</label>
                    <Input 
                      required 
                      value={name} 
                      onChange={e => setName(e.target.value)} 
                      placeholder="Ej. Juan Pérez"
                    />
                  </div>
                  <div className="flex flex-col gap-2">
                    <label className="text-sm font-medium text-gray-700">Correo Electrónico</label>
                    <Input 
                      required 
                      type="email" 
                      value={email} 
                      onChange={e => setEmail(e.target.value)} 
                      placeholder="usuario@empresa.com"
                    />
                  </div>
                </>
              )}

              {editingProfile && (
                <div className="bg-gray-50 px-4 py-3 rounded-lg border border-gray-100 mb-2">
                  <p className="text-sm font-medium text-gray-900">{editingProfile.name || 'Sin nombre'}</p>
                  <p className="text-xs text-gray-500">{editingProfile.email}</p>
                </div>
              )}

              <div className="flex flex-col gap-2">
                <label className="text-sm font-medium text-gray-700">Rol del Sistema</label>
                <select 
                  className="h-9 w-full rounded-lg border border-input bg-transparent px-3 text-sm outline-none focus-visible:ring-3 focus-visible:ring-ring/50 focus-visible:border-ring"
                  value={role}
                  onChange={e => setRole(e.target.value as UserRole)}
                >
                  <option value="owner">Owner (Propietario)</option>
                  <option value="admin">Admin (Administrador)</option>
                  <option value="supervisor">Supervisor</option>
                  <option value="member">Miembro (Técnico)</option>
                  <option value="guest">Invitado</option>
                </select>
              </div>

              <div className="flex items-center gap-3 mt-2">
                <input 
                  type="checkbox" 
                  id="isActive" 
                  checked={isActive}
                  onChange={e => setIsActive(e.target.checked)}
                  className="w-4 h-4 text-blue-600 rounded border-gray-300 focus:ring-blue-500"
                />
                <label htmlFor="isActive" className="text-sm font-medium text-gray-700 select-none cursor-pointer">
                  Cuenta Activa
                </label>
              </div>

              <div className="pt-4 flex gap-3 justify-end border-t border-gray-100 mt-2">
                <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)}>
                  Cancelar
                </Button>
                <Button type="submit" disabled={saving} className="bg-blue-600 hover:bg-blue-700 text-white min-w-[100px]">
                  {saving ? 'Guardando...' : 'Guardar'}
                </Button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}
